var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"계속 폭격해……!!","JPN":"爆撃をとめるな……！！","ENG":"Keep the bombardment going...!","TWN":"繼續轟炸！！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님이 녀석의 코어에 일격을 날릴 수 있도록 움직임을 봉쇄하는 거다!","JPN":"副戦隊長がやつのコアに一撃を食らわせられるよう、動きを封鎖するんだ！","ENG":"We're locking it down so the Deputy Commander can strike its core.","TWN":"副隊長會一擊命中那傢伙的核心，我們要封鎖它的行動！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중. 교전 속행 가능.</color>","JPN":"<color=#ff3636>損傷部位を修理中。交戦続行可能。</color>","ENG":"<color=#ff3636>Repairing damage. Ready to engage.</color>","TWN":"<color=#ff3636>正在維修損壞部位，可以繼續交戰。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_27"},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그래? 그럼 이것도 버틸 수 있을까……!","JPN":"そう？　ならこれも耐えられるかしら……！","ENG":"Oh yeah? Let's see if you can survive this...!","TWN":"是嗎？那這個你也能撐得住嗎……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위─── 수리 불───가.</color>","JPN":"<color=#ff3636>損傷部位───修理不───可。</color>","ENG":"<color=#ff3636>Damage... beyond repair...</color>","TWN":"<color=#ff3636>損壞部位───無法───維修。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_05"},{"id":"L18_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>시스템─── 다운──.</color>","JPN":"<color=#ff3636>システム───ダウン──。</color>","ENG":"<color=#ff3636>System... down...</color>","TWN":"<color=#ff3636>系統─── 停機──</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_08"},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이제 슬슬 활동 한계인가?","JPN":"そろそろ活動限界かな？","ENG":"It seems hitting my limit, huh?","TWN":"現在已經是活動的極限了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"분하지만, 아직 이 팔로 파동을 완전히 끌어내는 건 무리가 있네…….","JPN":"悔しいけど、この腕ではまだ波動を完全に引き出すのは無理があるわね……","ENG":"Damn... I still can't fully unleash the wave with this arm...","TWN":"雖然不甘心，但用這只手臂完全釋放波動還是有些勉強……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"고생하셨습니다, 부전대장님.","JPN":"お疲れさまでした、副戦隊長。","ENG":"You did great, Deputy Commander.","TWN":"辛苦了，副隊長。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"다들 수고 많았어, 얘들아. 너희들이 없었으면…… ","JPN":"みんなもお疲れ様。あなたたちがいなければ……","ENG":"Great work, everyone. I couldn't have done it without you...","TWN":"大家辛苦了，孩子們，要是沒有你們……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"무슨……!?","JPN":"どういう……！？","ENG":"What the...?!","TWN":"什麼……？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"작전 구역에서… 다수의 차원도약 신호 포착……!","JPN":"作戦区域から……多数の次元跳躍の信号を捕捉……！","ENG":"Wait... we're picking up multiple dimensional jump signals in the operation zone...!","TWN":"作戰區域內……發現多個次元跳躍訊號……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"설마, 이건……!?","JPN":"まさか、これは……！？","ENG":"No way... is that...?!","TWN":"難道……這是……？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"적성 개체 다수, 빠른 속도로 이쪽을 향하고 있습니다.","JPN":"敵性個体多数、高速でこちらに向かっています。","ENG":"Multiple hostiles incoming, closing in fast!","TWN":"敵性個體眾多，正快速向這邊靠近。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"일단, 물러나시죠, 부전대장님. 오늘 전장은 재활이었지 않습니까?","JPN":"一旦引き返しましょう、副戦隊長。本日の戦場はリハビリが目的だったはずです。","ENG":"For now, let's fall back, Deputy Commander. This was supposed to be rehab, wasn't it?","TWN":"先退下吧，副隊長。今天的戰場是康復訓練，不是嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"……맞는 말이야.","JPN":"……その通りよ。","ENG":"...You're right.","TWN":"……說得對。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그리고 어쩌면…….","JPN":"それに、もしかしたら……","ENG":"And maybe...","TWN":"而且，也許……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"상황이 생각했던 것보다 훨씬 심각할지도 모르겠네.","JPN":"状況が思ったよりもずっとよくないのかもしれない。","ENG":"Things might be a lot worse than we thought.","TWN":"看來情況比我想像的還要複雜啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤","JPN":"一週間後","ENG":"One week later","TWN":"一周後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>\\n아마니 밸리, 코핀 컴퍼니 임시 지부","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>\\nアマニーバレー、コフィンカンパニーの臨時支部","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>\\nAmani Valley, Temporary Coffin Company Branch","TWN":"管理局直屬城市<color=#ffd34c>洛德斯</color>\\n阿瑪尼山谷，科芬公司臨時分部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……지금까지의 경과는 이렇습니다.","JPN":"……これが、現時点までの成り行きです。","ENG":"...That's the situation so far.","TWN":"……事情的經過就是這樣的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시 자리를 비웠을 뿐인데, 그 사이에 많은 일들이 있었군.","JPN":"少々席を外したわりには、随分といろいろなことがあったようだな。","ENG":"I was only gone a short while, but it seems quite a lot has happened.","TWN":"只是暫時離開了一會兒，這期間發生了很多事情啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네, 알렉스 부전대장이 고생이 많았겠어.","JPN":"すまないね、アレックス副戦隊長に苦労を掛けてしまった。","ENG":"Thank you, Deputy Commander Alex. You've clearly been through a lot.","TWN":"謝謝你，雅蕾克絲副隊長，你辛苦了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로니아 사태에서 큰 부상을 입었다고 들었는데, 몸은 좀 괜찮나?","JPN":"グロニア事態で酷い怪我を負ったそうだが、身体の方は大丈夫なのかね？","ENG":"I heard you were seriously injured during the Gronia incident. How are you holding up?","TWN":"聽說你在格洛尼亞事件中受了重傷，身體還好嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후후, 자기가 걱정해 주니까, 왠지 기분이 좋은 걸?","JPN":"ふふ、ダーリンに心配されるなんて、なんだか嬉しいわ。","ENG":"Haha, I like your concern for me, honey.","TWN":"呵呵，因為你在擔心我，所以我感覺很好？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"고맙게 생각하고 있어, 관리자. 이렇게 전장에 다시 설 수 있는 건 자기 덕분이니까.","JPN":"感謝しているよ、管理者。こうして再び戦場に立てるのも、あなたのおかげよ。","ENG":"I'm truly grateful, Administrator. It's thanks to you that I'm able to stand on the battlefield again.","TWN":"非常感謝你，管理者，能再次站在戰場上都是托你的福。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"알파트릭스에서 제작한 유사 얼터니움 리액터였나?","JPN":"アルファトリックスで製作した、類似オルタニウムリアクターだっけ？","ENG":"That pseudo-Alternium Reactor produced by Alphatrix.","TWN":"是阿爾法崔克斯製作的仿製黑化永恆之金電抗器嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"지속시간이 짧은 것만 빼곤 제법 성능이 나쁘지 않던데?","JPN":"効果時間が短いことを除けばなかなか悪くない性能だったわ。","ENG":"Aside from the short uptime, the performance is actually quite decent.","TWN":"除了持續時間短，性能還不錯吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"자기가 또 무슨 마술을 부렸을까? 구 관리국 시절에도 그런 건 없었는데 말이야.","JPN":"またどんな魔法を使ったの、ダーリン？　旧管理局時代にもあんなものはなかったのに。","ENG":"What kind of trick did you pull this time? Not even the Old Administration had anything like this.","TWN":"她又施了什麼魔法呢？在舊管理局時期也沒有這種東西啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 기술이란 언제나 진보하기 마련이지.","JPN":"まあ、技術とは常に進歩するものさ。","ENG":"Well, technology's always moving forward.","TWN":"技術總是在不斷進步的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 너무 무리하지는 말게. 얼터니움 리액터라고 해도 만능은 아니니까.","JPN":"だが、あまり無理はしないでくれたまえ。オルタニウムリアクターとはいえど、万能というわけにはいかないのでね。","ENG":"Just don't push yourself too far. Even Alternium Reactors have limits.","TWN":"不過也不要太勉強，即使是黑化永恆之金電抗器也不是萬能的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후후, 걱정하지 마. 약도 잘 먹고, 선생님 말씀도 잘 듣고 있거든.","JPN":"ふふ、心配ご無用。薬もちゃんと飲んでいるし、先生の言うこともきちんと守っているもの。","ENG":"Haha, don't worry. I'm taking my meds and following the doctor's orders.","TWN":"哼哼，不用擔心，我有好好吃藥，也有聽博士的話。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"박정자라고 했던가? 나를 무슨 흥미로운 연구 대상으로 생각하더라?","JPN":"ナツキ・サチコと言ってたっけ。私を興味深い研究対象か何かだと思っていそうだったわ。","ENG":"Was her name Park Jeongja? She seemed to find me quite the fascinating test subject.","TWN":"叫朴靜子是吧？把我當成什麼有趣的研究物件了？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하여간 자기 여자 취향은 알다가도 모르겠어~","JPN":"まったく、ダーリンの好みってつくづくわからないわ～","ENG":"Seriously, I'll never understand your taste in women, honey.","TWN":"總之，我真搞不懂他的女性品味～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"뭐, 난 아량이 넓으니까 그다지 신경 쓰지 않지만.","JPN":"まあ、私は懐が広いからあまり気にしないけど。","ENG":"Not that I care. I'm pretty open-minded.","TWN":"嘛，我心胸寬廣，所以不怎麼在意。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하하……. 본인 앞에서는 그 이름을 삼가는 편이 좋을 걸세.","JPN":"ははは……本人の前でその名前は出さない方がいい。","ENG":"Haha... You might want to avoid saying that name in front of her.","TWN":"哈哈哈……在我面前最好不要提那個名字。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마침 모두 모여있었군.","JPN":"ちょうど集まっていたな。","ENG":"Good, everyone's here.","TWN":"正好大家都在這裡啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연, 네가 부탁한 대로 신입들을 데려왔다.","JPN":"カナミ、お前の頼みどおり新人たちを連れてきた。","ENG":"Lee Sooyeon, I brought the rookies you requested.","TWN":"李秀妍，我按照你的要求帶來了新員工。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안녕하세요, 관리자 씨. 그리고…… 부사장님?","JPN":"よろしくお願いします、管理者さん。そして……副社長さん？","ENG":"Hello, Mr. Administrator. And... Vice President?","TWN":"你好，管理員，還有……副總？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"신입들? 잠깐, 그럼 이 애도 우리 회사에서 일하게 되는 거야?","JPN":"新人たち？　ちょっと待ってよ、ってことはこの子もうちの会社で働くの？","ENG":"Rookies? Wait, does that mean this kid is joining our company too?","TWN":"新員工？等一下，那這個孩子也要在我們公司工作嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 본인의 의사가 가장 중요하겠지만 말이지.","JPN":"まあ、本人の意思が最優先だがな。","ENG":"Well, her own decision is what matters most.","TWN":"嗯，雖然本人的意願最重要。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래? 그럼 노엘이 선배가 되는 건가? 둘이 잘 지냈으면 좋겠네.","JPN":"そうか。じゃあノエルが先輩になるのかな？　仲良くしてあげてね。","ENG":"Oh yeah? Then I hope she gets along with Noelle.","TWN":"是嗎？那洛艾兒就是前輩了？希望你們兩個相處愉快。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"노엘?","JPN":"ノエル？","ENG":"Noelle?","TWN":"洛艾兒？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 소대장은 아직 모르나? 펜릴 소대에 새로 들어온 신입이야.","JPN":"あ、小隊長はまだ会ったことなかったっけ？　フェンリル小隊に新しく入った新入りだよ。","ENG":"Oh, you haven't heard yet? We've got a new rookie in the Fenrir Squad.","TWN":"啊，小隊長還不知道嗎？這是新加入芬里爾小隊的新人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"지금은 휴가 중이긴 한데…….","JPN":"今は休暇中だけど……","ENG":"She's technically on vacation right now...","TWN":"現在雖然是在休假中……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대에 신입이라고? 도통 무슨 소리를 하는 지 모르겠군.","JPN":"フェンリル小隊に新入り？　何を言っているのかさっぱりわからないぞ。","ENG":"A new rookie in the Fenrir Squad? What are you talking about?","TWN":"芬里爾小隊的新人？我完全不知道你在說什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐어? 관리부장님은 소대장이 아무나 뽑아도 상관없다고 했다던데?","JPN":"ええっ？　管理部長は小隊長から誰でも構わないと聞いているって言ってたよ？","ENG":"What? According to the Manager, you said we could pick whoever.","TWN":"什麼？管理部長說小隊長隨便選誰都無所謂？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오랜만이로군요, 스승님.","JPN":"師匠、お久しぶりです。","ENG":"It's been quite a long time, Master.","TWN":"許久不見，師父。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 오늘 퇴원한다고 들었는데, 몸은 좀 괜찮으신가요?","JPN":"ミナさんは今日退院だと聞きましたが、具合は大丈夫ですか？","ENG":"I heard you're being discharged today, Mina. Feeling better?","TWN":"米娜，我聽說你今天出院，身體還好嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"많이 좋아졌어. 이제 팔도 거의 다 나았고.","JPN":"うん、大分良くなったよ。腕もほぼ治ってきたし。","ENG":"Much better. My arm's almost fully healed now.","TWN":"好多了，現在胳膊也差不多好了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"부사장님은 어때? 이제 각혈하던 건 괜찮아?","JPN":"副社長はどうなの？　吐血は大丈夫になった？","ENG":"What about you, Vice President? Are you done coughing up blood?","TWN":"副總怎麼樣？現在咳血的情況好些了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 저는 괜찮습니다만…….","JPN":"ええ、私はまあ大丈夫なのですが……","ENG":"Oh, I'm fine...","TWN":"嗯，我倒是沒關係……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누군가의 방만 경영으로 인해, 회사의 재정 상황이 각혈하고 있어서 말이죠.","JPN":"誰かさんの放漫経営のせいで、会社の財政の方が吐血していますね。","ENG":"But our company's budget is the one bleeding out thanks to a certain someone's reckless management.","TWN":"由於某人的放任經營，公司財務狀況已經在吐血了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후… 그게 누구인지 참 궁금하군 그래…….","JPN":"ふふ……その誰かさんが誰なのか、非常に気になるところだな……","ENG":"Haha... I wonder who that someone could be...","TWN":"呵呵……真是好奇那是誰啊……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러게 말입니다. 저도 정말 궁금하군요.","JPN":"そうですね、私もとても気になります。","ENG":"Indeed. I'm quite curious myself.","TWN":"就是說啊，我也真的很好奇呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"한 회사의 CEO씩이나 되는 분이 적대 세력의 근거지에 당당히 들어가질 않나…….","JPN":"会社のCEOともあろうお方が、敵対勢力の本拠地に堂々と入り込み……","ENG":"I mean, what kind of CEO strolls right into enemy territory like it's nothing...?","TWN":"身為一家公司CEO的人，竟然堂而皇之地進入敵對勢力的據點……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러고 나선 갑자기 어디서 총을 맞고 와서 병원 신세를 지질 않나…….","JPN":"かと思えば、突然どこからか銃に撃たれて病院の世話になり……","ENG":"Then later, he’s got a bullet hole and ends up in the hospital…","TWN":"然後突然不知道從哪裡中槍住進了醫院……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하도 걱정돼서 로터스까지 날아왔건만, 이번에는 또 모르는 여자애를 데리고 왔다고 하죠?","JPN":"心配になりロータスまで飛んできてみれば、今度は見ず知らずの女の子を連れてきたと。","ENG":"I was so worried I flew all the way to Lotus, and what do I find? He's brought along some girl I've never even seen before.","TWN":"因為太擔心了，所以飛到了洛德斯，結果這次又帶來了一個不認識的女孩，對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 그 <color=#ffd34c>누군가</color>는 참 오지랖이 넓으신 분인가 봅니다?","JPN":"どうやらその<color=#ffd34c>誰かさん</color>は、非常にお世話好きのようですね？","ENG":"Seems like <color=#ffd34c>someone</color> just can't help getting involved in everything, huh?","TWN":"看來那位<color=#ffd34c>某人</color>真是個愛管閒事的人吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하, 하하… 용서해주게. 부사장. 늘 있는 일이지 않나?","JPN":"は、はは……許してくれたまえ、副社長。いつものことじゃないか。","ENG":"H-haha... Forgive me, Vice President. You know how it is with me.","TWN":"哈，哈哈……請原諒我，副總，這不是常有的事嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서? 그 아이는 누구죠?","JPN":"それで？　その子は誰ですか？","ENG":"So? Who is this child?","TWN":"所以呢？那孩子是誰？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"솔로베는 어머니의 딸이에요!","JPN":"ソロべーはお母さんの娘です！","ENG":"Solovey is Mother's daughter!","TWN":"蘇羅薇是母親的女兒！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 어머니의 뱃속에 있을 때, 관리자 씨가 떠나 버려서 두 분이 헤어지게 됐지만요!","JPN":"私がまだお母さんのお腹にいた時、管理者さんがどこかに行ってしまったので2人は別れることになったんです！","ENG":"When I was still in her womb, Mr. Administrator left her. That's why they broke up!","TWN":"在我還在母親肚子裡的時候，管理員先生就離開了，所以兩人分開了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 뭐라고요!?","JPN":"な、なんですって！？","ENG":"W-what did you just say?!","TWN":"什、什麼？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠깐! 오해라네, 부사장! 다른 건 몰라도 이것만큼은 정말로 오해야!","JPN":"待ってくれ！　誤解だ、副社長！　他はともかく、これだけは本当に誤解だ！","ENG":"Hold on! You've got it all wrong, Vice President! Whatever else you think, this one really is a misunderstanding!","TWN":"等等！這是誤會，副總！別的不說，這件事真的是誤會！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"힐데 소대장, 자네도 뭐라 설명을 좀……!","JPN":"ヒルデ小隊長、君からも何か説明を……！","ENG":"Commander Hilde, help me out here! Say something...!","TWN":"希爾德小隊長，你也解釋一下……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 왜?","JPN":"私が？　なぜ？","ENG":"Why should I?","TWN":"我為什麼要這樣做？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"관리자씨…….","JPN":"管理者さん……","ENG":"Mr. Administrator...","TWN":"管理員……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"부사장님? 왠지 저 아줌마 무서워요…….","JPN":"副社長さん？　なんか、あのおばさん怖いです……","ENG":"Vice President? That old lady's kind of scary...","TWN":"副總？總覺得那個阿姨好可怕……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아. 줌. 마……","JPN":"お・ば・さ・ん……","ENG":"Old... lady...?","TWN":"阿……姨……嗎……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"커헉!?","JPN":"カハッ！？","ENG":"Kuh?!","TWN":"呃？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"부, 부사장님이 또 각혈을……!","JPN":"ふ、副社長がまた吐血を……！","ENG":"V-Vice President's coughing up blood again...!","TWN":"副、副總又咳血了……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거… 병원 신세를 질 사람이 늘어 버렸군…….","JPN":"病院の世話になる人が増えてしまったな……","ENG":"Looks like we've got another one headed for the hospital...","TWN":"這下……需要住院的人變多了……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……쓸데없는 만담은 거기까지 하고 본론으로 들어가지.","JPN":"……くだらない茶番はそこまでにして、本題に入ろう。","ENG":"...Let's cut the idle chatter and get to the point.","TWN":"……廢話到此為止，進入正題吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연, 스완의 행방을 알아냈다고 들었는데.","JPN":"カナミ、スワンの行方がわかったとのことだが。","ENG":"Lee Sooyeon, I heard you've found Swan's whereabouts.","TWN":"李秀妍，我聽說你找到了史旺的下落。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 제자의 아픔을 쓸데없는 만담으로 치부해 버리다니…….","JPN":"こほん、弟子の苦痛をくだらない茶番とおっしゃるなんて……","ENG":"Ahem, calling an apprentice's suffering as mere idle chatter…","TWN":"咳，竟然把徒弟的痛苦當成無聊的閒聊……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"역시 스승님은 가차 없으시군요.","JPN":"相変わらず師匠は容赦ないですね。","ENG":"As ruthless as ever, Master.","TWN":"不愧是師父，完全不留情面呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난 최고등급 재난경보 이후, 스완이 마지막으로 목격된 로터스 항구 H-14입니다.","JPN":"先日の最高ランクの災難警報以降、スワンが最後に目撃されたロータスの港H-14です。","ENG":"After the last highest-level disaster alert, Swan was last seen at Lotus Port, Dock H-14.","TWN":"在上次最高級別災難警報之後，史旺最後一次被目擊是在洛德斯港口H-14。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"목격 증언에 따르면, 이곳에서 장도를 다루는 한 여성과 충돌이 있었던 것 같습니다.","JPN":"目撃証言によりますと、ここで剣を扱うある女性と揉めていたとのことです。","ENG":"According to eyewitnesses, she clashed with a woman wielding a sword.","TWN":"根據目擊者的證詞，這裡似乎發生了一起衝突，是與一名使用長刀的女性爆發的。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……또 나유빈의 떨거지들이로군.","JPN":"……またイチノセの輩か。","ENG":"...Na Yubin's band of strays again.","TWN":"……又是羅瑜斌的手下。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래서? 스완은 왜 항구로 향했던 거지?","JPN":"それで？　スワンはなぜ港に向かった？","ENG":"So why was Swan heading to the port?","TWN":"所以呢？史旺為什麼要去港口？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 스완은 이곳을 통해, 샤레이드로 밀입국을 시도하려 했던 것 같습니다.","JPN":"どうやらスワンはそこから、シャレードへの密入国を試みたようです。","ENG":"She likely tried to smuggle herself into Charade through that port.","TWN":"看來史旺是想透過這裡，試圖偷渡到查雷德。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 그로부터 얼마 뒤, 관리 경계 구역에 <color=#ffd34c>그것</color>이 출몰해 버렸죠.","JPN":"それからしばらくして、管理警戒区域に<color=#ffd34c>アレ</color>が出現しました。","ENG":"And not long after that... <color=#ffd34c>that thing</color> appeared in the perimeter zone.","TWN":"然後不久之後，管理邊界區域出現了<color=#ffd34c>那個</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……고철 더미.","JPN":"……鉄くず。","ENG":"...Scraps.","TWN":"……廢鐵堆。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"개인적인 추측이지만, 이 두 사건은 틀림없이 상관관계가 있을 겁니다.","JPN":"あくまで推測ですが、この2つの事件は間違いなく関係していると思われます。","ENG":"This is just my personal theory, but I'm certain the two incidents are connected.","TWN":"雖然是個人的推測，但這兩起事件肯定有關係。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"잠깐, 고철 더미라면… 설마, 소대장이 말했던 클리포트의 마왕을 말하는 거야……?","JPN":"待って、鉄くずってまさか……小隊長が言っていたクリフォトの魔王のこと……？","ENG":"Wait... Scraps? Are we talking about the Demon Lord of Qliphoth that you once mentioned...?","TWN":"等一下，如果是廢鐵堆的話……難道是指小隊長說的逆卡巴拉的魔王……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼, 그 커다란 우주선이 클리포트의 마왕이라고?","JPN":"じゃああのでっかい宇宙船がクリフォトの魔王？","ENG":"So you're saying... that massive spaceship is a Demon Lord of Qliphoth?","TWN":"那麼，那艘巨大的太空船就是逆卡巴拉的魔王嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 미나 양.","JPN":"その通りです、ミナさん。","ENG":"That's correct, Mina.","TWN":"是的，米娜。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"과거, 구 관리국을 궁지로 몰아넣었던 악몽 같은 녀석이죠.","JPN":"過去、旧管理局を窮地に追い込んだ悪夢のような存在。","ENG":"She's the same nightmare that once pushed the Old Administration to the brink.","TWN":"過去，是曾經將舊管理局逼入絕境的噩夢般的傢伙。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고철 더미, 양철 깡통, 기계장치의 마왕, 아시모프…….","JPN":"鉄くず、ブリキ缶、機械装置の魔王、アシモフ……","ENG":"Scraps, Junk Metal, Demon Lord of Machinery, Asimov…","TWN":"廢鐵堆、鐵皮罐頭、機械裝置之王、阿西莫夫……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"녀석에게 이런저런 별명은 많지만, 사실 녀석의 실체는 분명하지 않습니다.","JPN":"様々な別名がありますが、その実態は明らかになっていません。","ENG":"She goes by many names, but the truth is, no one really knows her true identity.","TWN":"那傢伙有各種各樣的綽號，但其實他的真面目並不明確。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그저 평소에는 우주를 부유하고 있다가, 어떤 특정한 조건을 트리거로 활동을 시작.","JPN":"普段はただ宇宙を浮遊するのみで、ある特定の条件をトリガーに活動を開始。","ENG":"She normally just floats in space, until a specific condition triggers her into action.","TWN":"平時只是漂浮在宇宙中，觸發某些特定條件後開始活動。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자신의 사도를 지구로 내려 보내, 수단과 방법을 가리지 않고 무차별 학살을 저지르죠.","JPN":"自分の使徒を地球に送り、手段を問わず無差別に人間を殺します。","ENG":"She then sends her Apostle down to Earth, carrying out indiscriminate massacres by any means necessary.","TWN":"派遣自己的使徒到地球，不擇手段地進行無差別屠殺。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……인류의 선별을 위해서.","JPN":"……人類の選別のために。","ENG":"...To select mankind.","TWN":"……為了篩選人類。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"인류의 선별이라고? 무슨 헛소리야?","JPN":"人類の選別だって？　それはまたふざけた理由ね。","ENG":"Select mankind? What kind of nonsense is that?","TWN":"篩選人類？你在胡說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"선별이라면서 왜 학살을 저지르는 건데?","JPN":"大体、選別なのにどうして虐殺なんてするの？","ENG":"If it's selection, then why the mass killings?","TWN":"既然是篩選，為什麼要進行屠殺？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기계가 기계로서의 사명을 다하듯.","JPN":"機械が機械としての使命を果たすように、","ENG":"Just as a machine fulfills its purpose as a machine...","TWN":"如同機器完成其作為機器的使命。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>방주</color>가 방주로서 사명을 다할 뿐이라네, 미나 양.","JPN":"<color=#ffd34c>箱舟</color>もまた箱舟としての使命を果たしているだけさ、ミナ君。","ENG":"An <color=#ffd34c>Ark</color> is simply fulfilling its purpose as an Ark, Mina.","TWN":"<color=#ffd34c>方舟</color>只是盡其作為方舟的使命罷了，米娜。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 인류를 구하는 것이 불가능하니, 구해야 하는 인간을 시험하고 선별하는 거지.","JPN":"全ての人類を救済することが不可能である以上、救うべき人間を試し、選別する。","ENG":"Since saving all of humanity is impossible, she tests and selects those deemed worthy of salvation.","TWN":"既然無法拯救全人類，那就要考驗並篩選出需要拯救的人類。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"애초에 마왕 아시모프의 정체는 <color=#ffd34c>코핀 오브 릴리스</color>의 네비게이션 시스템이거든.","JPN":"そもそも魔王アシモフの正体とは、<color=#ffd34c>コフィン・オブ・リリス</color>のナビゲーションシステムだからね。","ENG":"The Demon Lord Asimov is actually the navigation system of the <color=#ffd34c>Coffin of Lilith</color>.","TWN":"本來魔王阿西莫夫的真面目就是<color=#ffd34c>科芬·莉莉絲</color>的導航系統。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"방주라고? 그게 무슨……?","JPN":"箱舟だって？　それはどういう……？","ENG":"An Ark, you say? What are you talking about...?","TWN":"方舟？那是什麼……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방주라… 녀석이 관리국의 식별신호를 도용할 때부터 짐작은 하고 있었지만…….","JPN":"箱舟でしたか……やつが管理局の識別信号を無断で使用した時から感づいてはいましたが……","ENG":"An Ark, huh... I had my suspicions ever since she hijacked the Administration's identification signal.","TWN":"方舟啊……從那傢伙開始盜用管理局的識別訊號時，我就有所猜測了……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잘도 저런 괴물 같은 함선을 만들어 내셨군요, 사장님.","JPN":"よくもあんなバケモノ級の艦船を作られたものですね、社長。","ENG":"Still, that's one hell of a monstrous ship you've created, Boss.","TWN":"真有能耐，竟然造出了那樣的怪物艦船，老闆。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 각 마왕을 봉인하는 코핀 함의 메인 프레임은 기본적으로 동일한 구조라네.","JPN":"いや、各魔王を封印するコフィン艦のメインフレームは、基本的に同じ構造をしている。","ENG":"Not quite. The mainframe of the Coffin that seals each Demon Lord is built on the same structure.","TWN":"不，每個封印魔王的科芬艦主框架基本上是相同的結構。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 저건 마왕이 된 이후에 스스로를 보다 더 방주에 걸맞은 형태로 개조한 것이겠지.","JPN":"おそらくあれは、魔王になってから自分をより箱舟に相応しい形に改造したのだろう。","ENG":"That one likely modified herself after becoming a Demon Lord to better resemble an Ark.","TWN":"那大概是成為魔王之後，為了更適合方舟而改造了自己吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보다 더 많은 인류를 수용할 수 있는 형태로 말이야.","JPN":"より多くの人類を受け入れられる形にね。","ENG":"A form that could house even more humans.","TWN":"以能夠容納更多人類的形式。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"녀석이 클리포트 마왕인 이상, 어떤 형태든, 어떤 목적을 가졌든… 그런 건 중요하지 않아.","JPN":"やつがクリフォトの魔王である以上、どんな形で、どんな目的を持っているかはどうでもいい。","ENG":"It doesn't matter what form she takes or what goal she has, as long as she's a Demon Lord of Qliphoth.","TWN":"那傢伙既然是逆卡巴拉遊戲魔王，不管是什麼形態，什麼目的……那些都不重要。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"중요한 건, 녀석이 이 세계에 모습을 드러낸 이상, 싸워야 할 적이라는 거다.","JPN":"重要なのは、やつがこの世界に姿を現した以上、戦うべき敵だということだ。","ENG":"What does matter is that she appeared in this world and that makes her our enemy.","TWN":"重要的是，既然那傢伙已經在這個世界現身了，那就是我們必須與之戰鬥的敵人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래서? 대책은 생각해 두었겠지, 관리자?","JPN":"それで？　対策は考えてあるんだろうな、管理者。","ENG":"So? You've got a plan, don't you, Administrator?","TWN":"所以呢？你應該已經想好對策了吧，管理者？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아시모프는 오랜 시간 동안 여러 세계를 떠돌며 인류를 관측해 왔다네.","JPN":"アシモフは長い間、いろんな世界を漂い人類を観測してきた。","ENG":"Asimov has spent ages drifting between worlds, observing humanity.","TWN":"阿西莫夫長時間在多個世界中漂泊，觀察著人類。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"타기리온과 대적하고 있는 현시점에서 아시모프와 전면전을 벌이는 건 어리석은 짓이겠지.","JPN":"タギリオンと敵対している現時点で、アシモフと全面戦争に持ち込むのは愚策と言えるだろう。","ENG":"Engaging Asimov in a full-scale battle while we're still facing Thagirion would be reckless.","TWN":"在與塔基里翁對峙的現階段，與阿西莫夫全面開戰是愚蠢的行為。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파가 봉인되어 있다고 해도, 아시모프는 얼마든지 인류를 멸망시킬 방법을 알고 있을 테니까.","JPN":"クリファが封印されているとはいえ、アシモフはいくらでも人類を滅亡させる方法を知っているはずだからね。","ENG":"Even with Qlipha sealed away, Asimov likely knows more than enough ways to bring about humanity's end.","TWN":"即使逆卡巴拉被封印，阿西莫夫也一定知道毀滅人類的方法。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다만, 두 가지 신경 쓰이는 점이 있다네.","JPN":"ただ、2つだけ気になる点があるんだ。","ENG":"That said, there are two things that concern me.","TWN":"不過，有兩點需要注意。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"두 가지……?","JPN":"2つ……？","ENG":"Two things...?","TWN":"兩種……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"첫째, 아시모프가 나타난 곳이 어째서 샤레이드, 로터스의 관리 경계 구역인지…….","JPN":"1つ目、アシモフが現れた場所がどうしてシャレード、ロータスの管理警戒区域なのか……","ENG":"First, why did Asimov appear specifically in the Charade-Lotus perimeter zone...?","TWN":"首先，阿西莫夫出現的地方為什麼是查雷德和洛德斯的管理邊界區域……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"둘째, 모습을 드러낸 마왕이 어째서 일주일째 아무런 행동도 취하지 않고 있는 것인지…….","JPN":"2つ目、姿を現した魔王がどうして一週間も何も行動を起こさないのか……","ENG":"Second, why has the Demon Lord taken no action for an entire week after revealing herself...?","TWN":"第二，現身的魔王為什麼已經一周沒有採取任何行動……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아시모프는 철저히 정해진 기동 목적에 따라 움직인다네.","JPN":"アシモフは徹底的に定められた起動目的に従って動く。","ENG":"Asimov operates according to a strictly defined activation protocol.","TWN":"阿西莫夫嚴格按照既定的行動目的行事。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"따라서 우선 아시모프가 우리에게 무엇을 <color=#ffd34c>시험</color>하려는지 알아내는 것이 관건이겠지.","JPN":"つまり、まずはアシモフが我々の何を<color=#ffd34c>試し</color>たがっているのかを知るのが肝心だ。","ENG":"Which means our priority is figuring out what kind of <color=#ffd34c>test</color> she's trying to impose on us.","TWN":"因此，首先要弄清楚阿西莫夫想要對我們進行什麼<color=#ffd34c>測試</color>，這才是關鍵。"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군요. 고철 더미는 특정한 조건을 트리거 삼아 움직였으니까요.","JPN":"なるほど。鉄くずは特定の条件をトリガーに動き出す存在。","ENG":"I see. Scraps only activated when certain conditions were triggered.","TWN":"原來如此，廢鐵堆是在特定條件下被觸發而行動的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 트리거를 알아낼 수 있다면, 고철 더미의 판단을 보류시킬 수도 있다는 말씀이시군요.","JPN":"そのトリガーさえ突き止めることができれば、鉄くずの判断を保留させるのも可能ということですね。","ENG":"So if we can identify that trigger, we might be able to delay her decision-making.","TWN":"如果能找出那個觸發器，就能暫時擱置廢鐵堆的判斷。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면, 저희가 할 일은 분명합니다.","JPN":"でしたら、私たちのやるべきことは決まっています。","ENG":"In that case, our next move is clear.","TWN":"那麼，我們要做的事情很明確。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스완의 행방과 고철 더미의 출현은 그 맥락이 거의 일치하죠.","JPN":"スワンの行方と鉄くずの出現は、その脈絡がほぼ一致しています。","ENG":"There's a strong correlation between Swan's last known location and the appearance of Scraps.","TWN":"史旺的行蹤和廢鐵堆的出現幾乎是同時的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"따라서 고철 더미가 나타난 관리 경계 구역에서 무슨 일이 있었는지 밝혀내는 것입니다.","JPN":"つまり鉄くずが現れた管理警戒区域で何が起こったのか、それを明かせばいいということです。","ENG":"So we need to uncover what exactly happened in the perimeter zone where she appeared.","TWN":"因此要查明在出現廢鐵堆的管理邊界區域發生了什麼事。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……그러니까 미나 선배도 퇴원하시면, 저희 집에 놀러 오세요!","JPN":"……だからミナ先輩も退院したら、うちに遊びに来てください！","ENG":"...Once you're discharged, Mina, come hang out at my place!","TWN":"……所以米娜前輩出院後，也請來我家玩吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저희 집 과수원 사과로 만든 애플파이…! 잔뜩 대접해드릴 테니까요……!","JPN":"うちの果樹園で採れたりんごのアップルパイ……！　たくさんごちそうしますから……！","ENG":"I'll treat you to lots of apple pie, made from apples grown in our family orchard...!","TWN":"用我家果園的蘋果做的蘋果派……！我會好好招待你的……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……잠깐만. 부사장님.","JPN":"……ちょっと待って、副社長。","ENG":"...Hold on a sec, Vice President.","TWN":"……等一下，副總。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"별 건 아니고… 갑자기 생각난 거긴 한데…….","JPN":"大したことではないんだけど……急に思い出して……","ENG":"It's probably nothing, just something I suddenly remembered...","TWN":"沒什麼……只是突然想到……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"왜 그러시죠, 미나 양?","JPN":"ミナさん、どうしました？","ENG":"What is it, Mina?","TWN":"怎麼了，米娜？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우주선이 나타난 관리 경계 구역이라는 거, 어쩐지 노엘의 본가랑 가까운 것 같은데……?","JPN":"宇宙船が現れたっていう管理警戒区域って、ノエルの実家と近いんじゃない……？","ENG":"That perimeter zone where the spaceship appeared seems kinda close to Noelle's family home...?","TWN":"太空船出現在管理邊界區域，怎麼感覺離洛艾兒的老家很近……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"정확히는 기억 안 나지만, 나중에 놀러 오라고 노엘이 주소를 알려줬거든.","JPN":"ちょっとうろ覚えなんだけど、後で遊びに来いってノエルから住所を聞いたことがあるんだ。","ENG":"I don't remember the exact address, but she gave it to me once and said I should come visit sometime.","TWN":"雖然記不太清了，但洛艾兒後來告訴我地址，讓我有空去玩。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우선, 그 녀석에게 연락을 해봐야 하지 않을까?","JPN":"とりあえず、あの子に連絡するべきじゃないのかな？","ENG":"Shouldn't we try contacting her first?","TWN":"首先，應該聯絡那傢伙吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠?","JPN":"おっしゃる意味がわからないのですが？","ENG":"What do you mean?","TWN":"你在說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국 관리 경계 구역은 침식 지대입니다. 사람이 살 수가 없어요.","JPN":"管理局の管理警戒区域は侵食地帯です。人が住める場所ではありません。","ENG":"The perimeter zone is a Corrupted Area. It's uninhabitable.","TWN":"管理局管理的警戒區域是侵蝕地帶，人類無法生存。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아하하… 그게 무슨 소리야…? 그럴 리가 없잖아……?","JPN":"あはは……何言ってんの……？　そんなわけないじゃん……","ENG":"Hahaha... What are you talking about? That can't be right... Right?","TWN":"啊哈哈……你在說什麼啊……？怎麼可能呢……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아! 그렇지! 회사에 노엘의 이력서가 있을 거야!","JPN":"あ！　そうだ！　会社にノエルの履歴書があるはず！","ENG":"Ah! That's it! We should have Noelle's resume on file at the company.","TWN":"啊！對了！公司裡應該有洛艾兒的履歷表！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리 부장님께 연락해서 그걸 확인해 달라고 하면…….","JPN":"管理部長に連絡して、それを確認してもらえば……","ENG":"If we ask the Manager to check it...","TWN":"聯絡管理部長，讓他確認一下……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"노엘의 이력서……?","JPN":"ノエルの履歴書……？","ENG":"Noelle's resume...?","TWN":"洛艾兒的履歷書……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아까부터 무슨 말씀을 하고 계시는 거죠?","JPN":"先ほどから何をおっしゃっているのですか？","ENG":"What are you talking about?","TWN":"你從剛才開始在說什麼呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 노엘이 누구인가요? 샤레이드에서 새로 사귄 친구인가요?","JPN":"そもそもノエルとは誰のことでしょう？　シャレードで新しく出来たお友達ですか？","ENG":"Who's Noelle, anyway? Is she a new friend you made in Charade?","TWN":"洛艾兒是誰？是在查雷德新交的朋友嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……어, 어어?","JPN":"……え、ええ？","ENG":"...W-what?","TWN":"……啊啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"설마, 부사장님… 지금 노엘을 잊어버린 거야……?","JPN":"まさか、副社長……ノエルのことを忘れちゃったの……？","ENG":"Vice President, don't tell me... you've forgotten Noelle...?","TWN":"難道，副總……你現在把洛艾兒忘了嗎……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};